            Constructor<?> ctor = c.getConstructor(new Class[]{Graphics2D.class, Rectangle.class, Integer.TYPE, Integer.TYPE});
            Object state = ctor.newInstance(new Object[]{null, new Rectangle(0, 0, width, height), 0, 0});
            Method m = c.getMethod("getGraphics", new Class[]{});
            g2 = (Graphics2D) m.invoke(state);
        } catch (ClassNotFoundException | NoSuchMethodException | SecurityException | InstantiationException | IllegalAccessException | IllegalArgumentException | InvocationTargetException e) {
            // null will be returned
        }
        return g2;
    }

