target:
private void search(int[] input, int low, int high) {
        if (low > high) {
            return;
        }
        if (low == high) {
            System.out.println("The element is: " + input[low]);
            return;
        }
        int mid = (low + high) / 2;
        if (mid % 2 == 0) {
            if (input[mid] == input[mid + 1]) {
                search(input, mid + 2, high);
            } else {
                search(input, low, mid);
            }
        } else {
            if (input[mid] == input[mid - 1]) {
                search(input, mid - 2, high);
            } else {
                search(input, low, mid - 1);
            }
        }
    }

