@Override
    public void applyInPlace(FastBitmap sourceImage){
        int width = sourceImage.getWidth();
        int height = sourceImage.getHeight();
        int sizeOrigin = width * height;
        int sizeDestination = overlayImage.getWidth() * overlayImage.getHeight();
        if ((sourceImage.isGrayscale()) && (overlayImage.isGrayscale())) {
            if (sizeOrigin == sizeDestination) {
                int grayS,grayO;
                for (int x = 0; x < height; x++) {
                    for (int y = 0; y < width; y++) {
                        grayS = sourceImage.getGray(x, y);
                        grayO = overlayImage.getGray(x, y);
                        if ((grayS == 255) && (grayO == 255)) {
                            sourceImage.setGray(x, y, 255);
                        }
                        else{
                            sourceImage.setGray(x, y, 0);
                        }
                    }
                }
            }
        }
    }

prediction:
public void apply(FastBitmap source, FastBitmap destination) {
        if (overlayImage == null) {
            throw new IllegalArgumentException("Overlay image is not defined.");
        }
        if (source.getWidth()!= destination.getWidth() || source.getHeight()!= destination.getHeight()) {
            throw new IllegalArgumentException("Source and destination images must have the same size.");
        }
        if (source.getWidth()!= overlayImage.getWidth() || source.getHeight()!= overlayImage.getHeight()) {
            throw new IllegalArgumentException("Source and overlay images must have the same size.");
        }
        for (int y = 0; y < source.getHeight(); y++) {
            for (int x = 0; x < source.getWidth(); x++) {
                int sourcePixel = source.getPixel(x, y);
                int overlayPixel = overlayImage.getPixel(x, y);
                int destinationPixel = (sourcePixel & overlayPixel);
                destination.setPixel(x, y, destinationPixel);
            }
        }
    }

