private static Component renderGoal(Goal<?> goal, @Nullable Competitor competitor, Party party) {
    TextComponent.Builder msg = text();

    if (goal instanceof ProximityGoal) {
      ProximityGoal proximityGoal = (ProximityGoal) goal;
      msg.append(text(proximityGoal.getProximity(), NamedTextColor.GRAY));
    }

    if (goal.isShared()) {
      msg.append(text(TextTranslations.translate("match.info.shared", party), NamedTextColor.GRAY));
    } else if (competitor!= null) {
      msg.append(text(competitor.getName(), TextFormatter.convert(competitor.getColor())));
    }

    return msg.build();
  }

