	Optional<String> request = createRequest(message, page);

	if (!request.isPresent()) {

	    logger.warn("Invalid query parameters");
	    return new ResultSet();
	}

	Optional<HttpResponse<InputStream>> response = retrieve(message, page);

	if (!response.isPresent()) {

	    logger.warn("No response");
	    return new ResultSet();
	}

	logger.trace("Extracting data");

	ResultSet resultSet = extract(response.get());

	logger.info("Found {} results", resultSet.getResults().size());

	return resultSet;
    }

