        } catch (final IllegalArgumentException e) {
            throw JsonParseException.newBuilder()
                    .message(MessageFormat.format("Failed to deserialize value of key <{0}> as {1}: {2}",
                            fieldDefinition.getPointer(),
                            EntityType.class.getName(),
                            e.getMessage()))
                    .cause(e)
                    .build();
        }
    }

