@Override
  public void read(FileManipulator fm, Resource res, TaskProgressManager tpm) {

    try {

      // Header
      if (fm.readString(4).equals("FILE")) {
        fm.seek(4);
      }

      // Directory
      getDirectoryFile(fm.getFile(), "bod");

      // Read the file
      fm.seek(0);
      res.setFile(fm.getFile());
      res.setFileType(FileType.TYPE_MODEL);
      res.setFileData(new ByteBuffer(fm.getFile()));

    }
    catch (Throwable t) {
      ErrorLogger.logError(t);
    }

  }

