		 neighbors.add(space.getObjectAt(x1 - 1, y1));
		 neighbors.add(space.getObjectAt(x1 - 1, y1 - 1));
		 neighbors.add(space.getObjectAt(x1, y1 - 1));
		 return neighbors;
	 }

