@Override
    protected void validate(Annotation annotation, IIssueCallback issueCallback) {
        super.validate(annotation, issueCallback);

        if (annotation.getPatternElement()!= null) {
            // check if the item is a root
            if (annotation.getPatternElement().getPatternElement()!= null) {
                issueCallback.addIssue(annotation, HIERARCHY_LITERAL_ISSUE, "The item must be a root element.");
            }

            // check if the item is a port
            if (annotation.getPatternElement().getPatternElement() == null) {
                String hierarchy = getParameterValue(annotation, HIERARCHY_PARAMETER);
                if (hierarchy!= null &&!hierarchy.equals(HierarchyPolicy.ALWAYS.toString())) {
                    issueCallback.addIssue(annotation, HIERARCHY_LITERAL_ISSUE, "The item must be a port element.");
                }
            }
        }

        // check if the label is a string
        if (annotation.getPatternElement()!= null) {
            String label = getParameterValue(annotation, LABEL_PARAMETER);
            if (label!= null &&!PatternLanguageHelper.isStringValue(annotation.getPatternElement(), label)) {
                issueCallback.addIssue(annotation, LABEL_PARAMETER.getName(), "The label must be a string.");
            }
        }
    }

