target:
public static ListNode reverseKGroup(ListNode head, int k) {

        if (head == null || head.next == null) {
            return head;
        }
        ListNode cur = head;
        int count = 0;
        while (cur != null && count != k) {
            // 走K步
            cur = cur.next;
            count++;
        }
        if (count == k) {
            cur = reverseKGroup(cur, k);
            while (count-- > 0) {
                ListNode tmmp = head.next;
                head.next = cur;
                cur = head;
                head = tmmp;
            }
            head = cur;
        }
        return head;
    }

prediction:
public ListNode reverseKGroup(ListNode head, int k) {
         ListNode dummy = new ListNode(0);
         dummy.next = head;
         ListNode pre = dummy;
         ListNode cur = head;
         int count = 0;
         while (cur!= null) {
             count++;
             cur = cur.next;
             if (count == k) {
                 pre = reverse(pre, cur);
                 cur = pre.next;
                 count = 0;
             }
         }
         return dummy.next;
     }

