@Override
    public void appendTooltip(ItemStack stack, World world, List<Text> tooltip, TooltipContext context) {
        if (stack.hasNbt()) {
            NbtCompound strainTag = stack.getOrCreateSubNbt("cannacraft:strain");
            if (strainTag.contains("ID")) {
                StrainInterface strain = StrainUtil.getStrain(strainTag.getInt("ID"), strainTag.getBoolean("Resource"));
                if (strain!= null) {
                    strain.appendTooltip(stack, world, tooltip, context);
                }
            }
        }
        super.appendTooltip(stack, world, tooltip, context);
    }

