public void actionPerformed(java.awt.event.ActionEvent e) {
		if (e.getSource() == this.getBtOk()) {
			if (this.getTxtUser().getText().trim().length() == 0) {
				Funcoes.mensagemInforma(this, "Informe o usuário!");
				this.getTxtUser().requestFocus();
				return;
			}
			if (this.getTxtPass().getText().trim().length() == 0) {
				Funcoes.mensagemInforma(this, "Informe a senha!");
				this.getTxtPass().requestFocus();
				return;
			}
			if (this.getTxtUser().getText().trim().length() > 0
					&& this.getTxtPass().getText().trim().length() > 0) {
				try {
					DbConnection conn = new DbConnection(this.getTxtUser()
							.getText().trim(), this.getTxtPass().getText()
							.trim());
					conn.open();
					conn.close();
					this.dispose();
				} catch (Exception e1) {
					Funcoes.mensagemErro(this, e1.getMessage(), true,
							e1.getStackTrace());
					this.getTxtUser().requestFocus();
					return;
				}
			}
		} else if (e.getSource() == this.getBtCancel()) {
			this.dispose();
		}
	}
